INSERT INTO featureI18n VALUES('LqIGZkwk_dI5','en','''Wing Fat Hong Ltd.''',0,'Literally meaning “Song King Terrace” (宋王臺 sung3 wong4 toi4), this sign was originally carved on a massive boulder that crowned Sacred Hill. It commemorates the time when the last two Kings of the Southern Song Dynasty (1127–1279) passed through the area, taking shelter in the village of Ma Tau Chung, as they fled south from the Mongol invasion.',0,'69 Yuen Long On Hing St, Yuen Long',1,'{"buildingName":"On Hong Building","buildingNumberFrom":"69","streetName":"Yuen Long On Hing Street","neighbourhood":"Yuen Long","district":"YL","region":"NT","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('LqIGZkwk_dI5','zh-hant','''永發行有限公司''',1,'字面意思是“宋王臺”（宋王臺sung3 wong4 toi4），這個標誌最初雕刻在聖山的一塊巨石上。 佢係為咗紀念南宋嘅最後兩位國王（ 1127-1279年）在蒙古人入侵南下時經過該地區，在馬頭涌村避難。',1,'安康樓元朗安興街69號元朗區',1,'{"buildingName":"安康樓","buildingNumberFrom":"69","streetName":"元朗安興街","neighbourhood":"元朗","district":"元朗區","region":"新界","country":"香港特區"}');
INSERT INTO featureI18n VALUES('LqIGZkwk_dI5','zh-hans','''永发行有限公司''',1,'字面意思是“宋王台”（宋王臺 sung3 wong4 toi4），这个标志最初雕刻在圣山的一块巨石上。它是为了纪念南宋的最后两位国王（1127-1279 年）在蒙古人入侵南下时经过该地区，在马头涌村避难。',1,'安康楼元朗安兴街69号元朗区',1,'{"buildingName":"安康楼","buildingNumberFrom":"69","streetName":"元朗安兴街","neighbourhood":"元朗","district":"元朗区","region":"新界","country":"香港特区"}');
