INSERT INTO featureI18n VALUES('gra3PJsUoOpv','zh-hans','“协成地产有限公司”',1,NULL,0,'元祥楼元朗安兴街1号元朗区',1,'{"buildingName":"元祥楼","buildingNumberFrom":"1","streetName":"元朗安兴街","neighbourhood":"元朗","district":"元朗区","region":"新界","country":"香港特区"}');
INSERT INTO featureI18n VALUES('z4WT9zI08T_a','en','''__Ltd.''',0,'The two boy emperors, Zhao Shi and Zhao Bing, were around 7 and 6 years old when they arrived on a boat in the middle of a typhoon. The story goes that one of the boys observed the eight mountain peaks looming over the peninsula and declared them to be eight dragons. “The area should henceforth be known as Kowloon (‘Nine Dragons’ 九龍 gau2 lung4)” the boy emperor proclaimed. Confused, a courtier asked why it should be so named if there were only eight mountains. “It is I,” explained the emperor. “I am the ninth dragon!”',0,'2 Kam Fai Path, Yuen Long',1,'{"buildingName":"Kam On Building","buildingNumberFrom":"2","streetName":"Kam Fai Path","neighbourhood":"Yuen Long","district":"YL","region":"NT","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('z4WT9zI08T_a','zh-hant','“__Ltd。”',1,'兩位少年皇帝赵石同赵冰喺颱風中乘船到達時，分別係7岁同6岁。 故仔咁嘅，其中一個男孩觀察到半島上若隱若現嘅八座山峰，並宣佈它們係八條龍。 “從今以後，這片地區應該被稱為九龍（''九龍''九仞gau2 lung4），”少年皇帝宣佈。 一位朝臣困惑地問道，如果只有八座山，點解仲要咁命名。 “是我，”皇帝解釋道。 “我係第九条龍！”',1,'金安閣金輝徑2號元朗區',1,'{"buildingName":"金安閣","buildingNumberFrom":"2","streetName":"金輝徑","neighbourhood":"元朗","district":"元朗區","region":"新界","country":"香港特區"}');
INSERT INTO featureI18n VALUES('z4WT9zI08T_a','zh-hans','“__Ltd。”',1,'两位少年皇帝赵石和赵冰在台风中乘船到达时，分别是 7 岁和 6 岁。故事是这样的，其中一个男孩观察到半岛上若隐若现的八座山峰，并宣布它们是八条龙。“从今以后，这片地区应该被称为九龙（''九龙''九龍 gau2 lung4），”少年皇帝宣布。一位朝臣困惑地问道，如果只有八座山，为什么还要这样命名。“是我，”皇帝解释道。“我是第九条龙！”',1,'金安阁金辉径2号元朗区',1,'{"buildingName":"金安阁","buildingNumberFrom":"2","streetName":"金辉径","neighbourhood":"元朗","district":"元朗区","region":"新界","country":"香港特区"}');
