INSERT INTO featureI18n VALUES('VMxO8Y2sdi_u','en','Dance Studio & Pianos',0,'Zhao Shi would die of illness about a year into their sojourn and his brother soon followed. The Song made its last stand at the Battle of Yamen in 1279, where the Mongols defeated the Song Navy. Knowing this was the end, a loyal retainer put Zhao Bing on his shoulders and jumped from a cliff, killing them both.',0,'35 Tai Tong Rd, Yuen Long',1,'{"buildingName":"Hung Min Building","buildingNumberFrom":"35","streetName":"Tai Tong Road","neighbourhood":"Yuen Long","district":"YL","region":"NT","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('VMxO8Y2sdi_u','zh-hant','舞蹈工作室和鋼琴',1,'赵石喺佢哋逗留大約一年後因病去世，佢兄弟好快都隨之而來。 宋朝喺1279年嘅衙門戰役中進行了最後的抵抗，蒙古人喺呢場戰役中擊敗咗宋朝海軍。 一個忠心耿耿嘅家臣知就係結局，將赵冰扛在肩上，從懸崖上跳咗落嚟，殺死咗佢哋兩人。',1,'紅棉洋樓大棠路35號元朗區',1,'{"buildingName":"紅棉洋樓","buildingNumberFrom":"35","streetName":"大棠路","neighbourhood":"元朗","district":"元朗區","region":"新界","country":"香港特區"}');
INSERT INTO featureI18n VALUES('VMxO8Y2sdi_u','zh-hans','舞蹈工作室和钢琴',1,'赵石在他们逗留大约一年后因病去世，他的兄弟很快也随之而来。宋朝在 1279 年的衙门战役中进行了最后的抵抗，蒙古人在这场战役中击败了宋朝海军。一个忠心耿耿的家臣知道这就是结局，把赵冰扛在肩上，从悬崖上跳了下来，杀死了他们两人。',1,'红棉洋楼大棠路35号元朗区',1,'{"buildingName":"红棉洋楼","buildingNumberFrom":"35","streetName":"大棠路","neighbourhood":"元朗","district":"元朗区","region":"新界","country":"香港特区"}');
