INSERT INTO featureI18n VALUES('58MOsJp8Y5s2','en','''_Hok__Man Li__''',0,'From the start Hong Kong has existed at the unlikely intersection of chance and change. A modest record of these origins, the Ghost Signs of Hong Kong are guardians of this city’s rich history and identity.',0,'48 Tai Tong Rd, Yuen Long',1,'{"buildingName":"On Fook Building","buildingNumberFrom":"48","streetName":"Tai Tong Road","neighbourhood":"Yuen Long","district":"YL","region":"NT","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('58MOsJp8Y5s2','zh-hant','“_Hok__Man Li__”',1,'由一開始，香港就存在於機會和變化之間。 香港嘅鬼星座係呢啲起源嘅樸素記錄，係這座城市豐富歷史同身份嘅守護者。',1,'安福大樓大棠路48號元朗區',1,'{"buildingName":"安福大樓","buildingNumberFrom":"48","streetName":"大棠路","neighbourhood":"元朗","district":"元朗區","region":"新界","country":"香港特區"}');
INSERT INTO featureI18n VALUES('58MOsJp8Y5s2','zh-hans','“_Hok__Man Li__”',1,'从一开始，香港就存在于机会和变化之间。香港的鬼星座是这些起源的朴素记录，是这座城市丰富历史和身份的守护者。',1,'安福大楼大棠路48号元朗区',1,'{"buildingName":"安福大楼","buildingNumberFrom":"48","streetName":"大棠路","neighbourhood":"元朗","district":"元朗区","region":"新界","country":"香港特区"}');
