INSERT INTO featureI18n VALUES('MXIE5JZvVxSU','zh-hans','Chiu Hok Yin Ving Tsun Kung Fu',1,NULL,0,'远东楼西堤街10号元朗区',1,'{"buildingName":"远东楼","buildingNumberFrom":"10","streetName":"西堤街","neighbourhood":"元朗","district":"元朗区","region":"新界","country":"香港特区"}');
INSERT INTO featureI18n VALUES('Ef656XCeCjs8','en','Wing Tong Store',0,'Seemingly invisible to passers-by unattuned to these relics of the past, such phantom outlines of old signage are sometimes referred to as ‘revenants,’ left behind like an afterimage burned into the signboard, the retina, and the memory.',0,'2 Kin Tak St, Yuen Long',1,'{"buildingName":"Shun Hing Building","buildingNumberFrom":"2","streetName":"Kin Tak Street","neighbourhood":"Yuen Long","district":"YL","region":"NT","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('Ef656XCeCjs8','zh-hant','永棠店',1,'對於唔熟悉呢啲過去遺蹟嘅路人來說，呢啲幻影輪廓似乎係睇唔見嘅，呢種舊標牌嘅幻影輪廓有時被稱為“亡魂”，就好似烙印喺招牌、視網膜和記憶中嘅殘影一樣留低。',1,'順興大樓建德街2號元朗區',1,'{"buildingName":"順興大樓","buildingNumberFrom":"2","streetName":"建德街","neighbourhood":"元朗","district":"元朗區","region":"新界","country":"香港特區"}');
INSERT INTO featureI18n VALUES('Ef656XCeCjs8','zh-hans','永棠店',1,'对于不熟悉这些过去遗迹的路人来说，这些幻影轮廓似乎是看不见的，这种旧标牌的幻影轮廓有时被称为“亡魂”，就像烙印在招牌、视网膜和记忆中的残影一样留下来。',1,'顺兴大楼建德街2号元朗区',1,'{"buildingName":"顺兴大楼","buildingNumberFrom":"2","streetName":"建德街","neighbourhood":"元朗","district":"元朗区","region":"新界","country":"香港特区"}');
INSERT INTO featureI18n VALUES('X2Hu0SrFZ8Ft','en','Man Bo Herb Shop',0,replace('We spotted this Yuen Long Ghost Sign for 萬寶藥行 (maan6 bou2 joek6 hang4 ‘Man Po Pharmacy’) just in time. We were told by the new occupants, a family run snack shop selling delicious samosas, that it would be removed later that evening along with the green awning (which bears Man Po’s name in yellow).\n\nThe shopkeepers were understandably concerned to see us taking photos of their brand new eatery - it’s hard to get a small business up and running and this must represent a huge investment. Who needs nosy food inspectors to come in and ruin things at the last minute? Luckily for everyone it was just a couple hungry Ghost Sign hunters.','\n',char(10)),0,'68 Hop Yick Rd, Yuen Long',1,'{"buildingName":"Yuk Sau Building","buildingNumberFrom":"68","streetName":"Hop Yick Road","neighbourhood":"Yuen Long","district":"YL","region":"NT","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('X2Hu0SrFZ8Ft','zh-hant','Man Bo香草店',1,replace('我哋及時發現咗呢個元朗鬼牌（ maan6 bou2 joek6 hang4 ''Man Po Pharmacy''）。 新住戶係一家出售美味咖喱角嘅家庭經營小喫店，我哋話畀它，它將在當晚遲啲與綠色遮陽篷（黃色印有文寶嘅名）一起被拆除。\n\n可以理解嘅係，店主們睇到我哋為佢哋全新嘅餐館拍照-好難畀小企業啟動和運行，必須代表住巨大嘅投資。 邊個需要愛管閒事嘅食品檢查員喺最後一刻入嚟毀掉事情呢？ 幸運嘅係，只係幾個飢餓嘅Ghost Sign獵人。','\n',char(10)),1,'毓秀樓合益路68號元朗區',1,'{"buildingName":"毓秀樓","buildingNumberFrom":"68","streetName":"合益路","neighbourhood":"元朗","district":"元朗區","region":"新界","country":"香港特區"}');
INSERT INTO featureI18n VALUES('X2Hu0SrFZ8Ft','zh-hans','Man Bo 香草店',1,replace('我们及时发现了这个元朗鬼牌 （maan6 bou2 joek6 hang4 ''Man Po Pharmacy''）。新住户是一家出售美味咖喱角的家庭经营小吃店，我们告诉它，它将在当晚晚些时候与绿色遮阳篷（黄色印有文宝的名字）一起被拆除。\n\n可以理解的是，店主们看到我们为他们全新的餐馆拍照 - 很难让小企业启动和运行，这必须代表着巨大的投资。谁需要爱管闲事的食品检查员在最后一刻进来毁掉事情呢？幸运的是，这只是几个饥饿的 Ghost Sign 猎人。','\n',char(10)),1,'毓秀楼合益路68号元朗区',1,'{"buildingName":"毓秀楼","buildingNumberFrom":"68","streetName":"合益路","neighbourhood":"元朗","district":"元朗区","region":"新界","country":"香港特区"}');
INSERT INTO featureI18n VALUES('up1j7553y3Jc','en','Beach Side Locker Rental',0,NULL,0,'3 Tung Wan Rd, Cheung Chau',1,'{"buildingNumberFrom":"3","streetName":"Tung Wan Road","neighbourhood":"Cheung Chau","district":"ILD","region":"NT","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('up1j7553y3Jc','zh-hant','Beach Side儲物櫃租賃',1,NULL,0,'東灣路3號離島區',1,'{"buildingNumberFrom":"3","streetName":"東灣路","neighbourhood":"長洲","district":"離島區","region":"新界","country":"香港特區"}');
INSERT INTO featureI18n VALUES('up1j7553y3Jc','zh-hans','Beach Side 储物柜租赁',1,NULL,0,'东湾路3号离岛区',1,'{"buildingNumberFrom":"3","streetName":"东湾路","neighbourhood":"长洲","district":"离岛区","region":"新界","country":"香港特区"}');
INSERT INTO featureI18n VALUES('fklrF4FvX0j0','en','Kent Cigarette Advert',0,replace('We’ve got it made in the shade out on Cheung Chau\n\nThis island is packed to the gills with amazing history, from the 19th century cave hideout of the pirate, Cheung Po Tsai, to the derelict 1930s Cheung Chau Cinema (長洲戲院 coeng4 zau1 hei3 jyun2). There are temples from the 18th Century, and even an alternative ‘Peak’ that was once reserved as a summer retreat for foreign missionaries.\n\nPeople have lived on and around Cheung Chau for at least 3,000 years - just look to the ancient rock carvings near Tung Wan Beach for proof. With settlements going back so far, it’s not surprising that we found lots of Ghost Signs while soaking up the sleepy island ambience.\n\nA short walk from the Bronze Age rock carvings, but not quite as old, we found these Ghost Signs at a laid back beachside bar - you might even consider them palimpsests. We think we can just about make out the characters, “海濱” (hoi2 ban1 waterfront), painted on a pillar. It could just be some old worn out signage from the same business. It’s been painted over a couple times at least and these days the shop seems to prioritise ads for frosty beers and their locker rental service (bad luck if you want a small one by the looks of it).\n\nJust across to the right, revealed from under what looks to have been a mural and some illegible Chinese characters, is an old ad for Kent cigarettes. Since beaches are designated ‘statutory no smoking areas’ in Hong Kong, there won’t be much call for smokes these days but we still got a kick out of identifying the obscure lettering from their tell-tale yellow and blue colour scheme!','\n',char(10)),0,'3 Tung Wan Rd, Cheung Chau',1,'{"buildingNumberFrom":"3","streetName":"Tung Wan Road","neighbourhood":"Cheung Chau","district":"ILD","region":"NT","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('fklrF4FvX0j0','zh-hant','Kent香煙廣告',1,replace('我哋喺長洲嘅陰涼處製作了它\n\n呢個島嶼擁有令人驚嘆嘅歷史，從19世紀海盜张宝仔嘅洞穴藏身處，到1930年代廢棄嘅長洲電影院（長洲雒民coeng4 zau1 hei3 jyun2 ）。 呢度有18世紀嘅寺廟，甚至仲有另一個徜徉山頂徜徉，它曾經被保留為外國傳教士嘅避暑勝地。\n\n啲人喺長洲及其周邊地區生活咗至少3,000年——睇下東灣海灘附近嘅古老石刻就收到。 隨著定居點嘅歷史可以追溯到好耐以前，我哋喺沉浸沉睡緊嘅島嶼氛圍中發現咗好多Ghost Signs都就不足為奇埋。\n\n距離青銅時代嘅石刻唔遠，但唔係咁古老，我哋喺一個悠閒嘅海濱酒吧發現咗呢啲鬼標誌-你甚至可以認為它們係抄本。 我們認為我們幾乎可以辨認出畫在柱子上的字符“海濱”（hoi2 ban1 waterfront）。 它可能只係同一家企業的一些破舊嘅標牌。 它至少被粉刷了好幾次，呢啲日嚟，呢間店似乎優先考慮Frosty Beer同佢哋嘅儲物櫃租賃服務嘅廣告（如果你想要一個細嘅，從外觀上睇就好倒霉了）。\n\n就在右對面，從看起來像壁畫和一些難以辨認嘅漢字下面露出嚟嘅係肯特香煙嘅舊廣告。 由於海灘係香港指定嘅“法定禁煙區”，而家唔會有太多嘅食煙呼籲，但我哋仍然由佢哋明顯嘅黃色同藍色配色方案中識別出晦澀嘅字母！','\n',char(10)),1,'東灣路3號離島區',1,'{"buildingNumberFrom":"3","streetName":"東灣路","neighbourhood":"長洲","district":"離島區","region":"新界","country":"香港特區"}');
INSERT INTO featureI18n VALUES('fklrF4FvX0j0','zh-hans','Kent 香烟广告',1,replace('我们在长洲的阴凉处制作了它\n\n这个岛屿拥有令人惊叹的历史，从 19 世纪海盗张宝仔的洞穴藏身处，到 1930 年代废弃的长洲电影院（长洲戲院 coeng4 zau1 hei3 jyun2）。这里有 18 世纪的寺庙，甚至还有另一个“山顶”，它曾经被保留为外国传教士的避暑胜地。\n\n人们在长洲及其周边地区生活了至少 3,000 年——看看东湾海滩附近的古老石刻就知道了。随着定居点的历史可以追溯到很久以前，我们在沉浸在沉睡的岛屿氛围中发现了很多 Ghost Signs 也就不足为奇了。\n\n距离青铜时代的石刻不远，但不是那么古老，我们在一个悠闲的海滨酒吧发现了这些鬼标志 - 你甚至可以认为它们是抄本。我们认为我们几乎可以辨认出画在柱子上的字符“海濱”（hoi2 ban1 waterfront）。它可能只是同一家企业的一些破旧的标牌。它至少被粉刷了好几次，这些天来，这家店似乎优先考虑 Frosty Beer 和他们的储物柜租赁服务的广告（如果你想要一个小的，从外观上看就很倒霉了）。\n\n就在右对面，从看起来像壁画和一些难以辨认的汉字下面露出来的是肯特香烟的旧广告。由于海滩是香港指定的“法定禁烟区”，现在不会有太多的吸烟呼吁，但我们仍然从他们明显的黄色和蓝色配色方案中识别出晦涩的字母！','\n',char(10)),1,'东湾路3号离岛区',1,'{"buildingNumberFrom":"3","streetName":"东湾路","neighbourhood":"长洲","district":"离岛区","region":"新界","country":"香港特区"}');
