INSERT INTO featureI18n VALUES('E5EwDPBoTOHa','en','''Lung Wah Theatre''',0,replace('We visited on a gray, rainy day, the type when it''s nice to catch a movie. However, if you’re at the Lung Wah Theatre/ 龍華戲院, you''re out of luck. \n\nBuilt in 1962, Lung Wah served its neighbourhood of Tsuen Wan until 1996, screening both Chinese and English films. \n\nThe theatre’s modernist building remains but these days you''ll have to trade your popcorn for realty listings. There’s not much left of that old show business magic but on the facade you can still glimpse the remains of the cinema’s signage, picked out in exposed concrete. Nothing but a Ghost Sign to enjoy while the rain falls.','\n',char(10)),0,'77 Yeung Uk Rd, Tsuen Wan',1,'{"buildingNumberFrom":"77","streetName":"Yeung Uk Road","neighbourhood":"Tsuen Wan","district":"TW","region":"NT","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('E5EwDPBoTOHa','zh-hant','閰龍華劇場 ㄏ',1,replace('我哋喺一個灰濛濛的雨天參觀，那種睇電影好唔錯嘅日子。 但是，如果您在龍華劇院/ \n\n龍華醫院建於1962年，服務於荃灣附近直至1996年開，放映中英文電影。 \n\n劇院嘅現代主義建築仍然存在，但如今，你將不得不用爆谷換取地產清單。 昔日嘅演藝界魔力已經所剩無幾，但在外牆上，你仍然可以瞥見電影院標牌嘅遺蹟，呢啲標牌係喺裸露嘅混凝土中挑選出嚟嘅。 除咗一個可以喺落雨時享受嘅鬼星座之外，別無他物。','\n',char(10)),1,'楊屋道77號荃灣區',1,'{"buildingNumberFrom":"77","streetName":"楊屋道","neighbourhood":"荃灣","district":"荃灣區","region":"新界","country":"香港特區"}');
INSERT INTO featureI18n VALUES('E5EwDPBoTOHa','zh-hans','''龙华剧场''',1,replace('我们在一个灰蒙蒙的雨天参观，那种看电影很不错的日子。但是，如果您在龙华剧院/\n\n龙华医院建于 1962 年，一直服务于荃湾附近直至 1996 年，放映中英文电影。\n\n剧院的现代主义建筑仍然存在，但如今，您将不得不用爆米花换取房地产清单。昔日的演艺界魔力已经所剩无几，但在外墙上，您仍然可以瞥见电影院标牌的遗迹，这些标牌是在裸露的混凝土中挑选出来的。除了一个可以在下雨时享受的鬼星座之外，别无他物。','\n',char(10)),1,'杨屋道77号荃湾区',1,'{"buildingNumberFrom":"77","streetName":"杨屋道","neighbourhood":"荃湾","district":"荃湾区","region":"新界","country":"香港特区"}');
