INSERT INTO featureI18n VALUES('AZci-xdRkLa7','en','''Man Kee Decoration Company''',0,'As per Hong Kong signage expert, Li Kin-ming in his book ''你看香港招牌'' (Looking at Hong Kong Signage), yellow is a relatively little used colour in Hong Kong signage because historically the colour was linked to signage for pornography theatres and shops associated with pornography. With the associaiton waning, we are likely to see yellow appearing in more modern signs.',0,'114 First St, Sai Wan',1,'{"buildingNumberFrom":"114","streetName":"First Street","neighbourhood":"Sai Wan","district":null,"region":"HK","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('AZci-xdRkLa7','zh-hant','''萬記裝飾公司''',1,'根據香港標牌專家李健明喺佢嘅《你睇香港招牌》書中嘅講法，黃色喺香港標牌中係一種相對較少使用嘅色水，因為從歷史上睇，呢種顏色與色情劇院同與色情相關嘅舖頭嘅標牌有關。 隨著關聯性嘅減弱，我哋可能會睇到黃色出現喺更現代嘅標誌中。',1,'第一街114號中西區',1,'{"buildingNumberFrom":"114","streetName":"第一街","neighbourhood":"西環","district":"中西區","region":null,"country":"香港特區"}');
INSERT INTO featureI18n VALUES('AZci-xdRkLa7','zh-hans','''万记装饰公司''',1,'根据香港标牌专家李健明在他的《你看香港招牌》一书中的说法，黄色在香港标牌中是一种相对较少使用的颜色，因为从历史上看，这种颜色与色情剧院和与色情相关的商店的标牌有关。随着关联性的减弱，我们可能会看到黄色出现在更现代的标志中。',1,'第一街114号中西区',1,'{"buildingNumberFrom":"114","streetName":"第一街","neighbourhood":"西环","district":"中西区","region":null,"country":"香港特区"}');
