INSERT INTO featureI18n VALUES('2QRaLxG7bHgZ','zh-hans','“华兴蔬果”',1,NULL,0,'石排湾道84号南区',1,'{"buildingNumberFrom":"84","streetName":"石排湾道","neighbourhood":"香港人","district":"南区","region":null,"country":"香港特区"}');
INSERT INTO featureI18n VALUES('EUYajToAnSaB','en','''Hang Tung, Ban Cam__''',0,replace('The little neighbourhood of Tin Wan sits just West of Aberdeen, not far from the Aberdeen Wholesale Fish Market. According to the 1911 census, Tin Wan had 111 people (67 males). Today it’s still a nice little community with neighbourhood shops and restaurants - the population has increased somewhat though (17,012 according to the 2016 census).\n\nUntil recently, the neighbourhood has retained a lot of its own character with relatively few chain shops and businesses but we could soon see major change in Tin Wan, just like with its trendy neighbours, Ap Lei Chau and Wong Chuk Hang.\n\nThis is one example of an old Tin Wan shop which has recently closed after decades in business. Let’s hope that Tin Wan can hold on to some of its old charm long into the future.','\n',char(10)),0,'87 Shek Pai Wan Rd, Aberdeen',1,'{"buildingNumberFrom":"87","streetName":"Shek Pai Wan Road","neighbourhood":"Aberdeen","district":"STH","region":"HK","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('EUYajToAnSaB','zh-hant','雒杭东，潘Cam__徜徉',1,replace('天灣小區位於香港仔以西，距離香港仔魚類批發市場不遠。 根據1911年嘅人口普查，田灣有111人（ 67名男性）。 今天，它仍然係一個唔錯嘅小社區，附近有舖頭同餐館-不過人口有所增加（根據2016年人口普查為17,012人）。\n\n直到最近，該社區仲保留咗好多自己嘅特色，連鎖店和企業相對較少，但我哋好快就會睇到田灣嘅重大變化，就好似它的時尚鄰居鴨脷洲同黃竹坑一樣。\n\n係一家老天灣店嘅一個例子，該店喺經營咗幾十年後最近關閉。 畀我哋希望天灣能夠喺未來很長一段時間內保持它昔日嘅魅力。','\n',char(10)),1,'石排灣道87號南區',1,'{"buildingNumberFrom":"87","streetName":"石排灣道","neighbourhood":"香港仔","district":"南區","region":null,"country":"香港特區"}');
INSERT INTO featureI18n VALUES('EUYajToAnSaB','zh-hans','“杭东，潘Cam__”',1,replace('天湾小区位于香港仔以西，距离香港仔鱼类批发市场不远。根据 1911 年的人口普查，田湾有 111 人（67 名男性）。今天，它仍然是一个不错的小社区，附近有商店和餐馆 - 不过人口有所增加（根据 2016 年人口普查为 17,012 人）。\n\n直到最近，该社区还保留了很多自己的特色，连锁店和企业相对较少，但我们很快就会看到田湾的重大变化，就像它的时尚邻居鸭脷洲和黄竹坑一样。\n\n这是一家老天湾店的一个例子，该店在经营了几十年后最近关闭。让我们希望天湾能够在未来很长一段时间内保持它昔日的魅力。','\n',char(10)),1,'石排湾道87号南区',1,'{"buildingNumberFrom":"87","streetName":"石排湾道","neighbourhood":"香港人","district":"南区","region":null,"country":"香港特区"}');
INSERT INTO featureI18n VALUES('3SHUxTLaXa_7','en','''Ji Zang Can Yat_Hak__''',0,replace('The little neighbourhood of Tin Wan sits just West of Aberdeen, not far from the Aberdeen Wholesale Fish Market. According to the 1911 census, Tin Wan had 111 people (67 males). Today it’s still a nice little community with neighbourhood shops and restaurants - the population has increased somewhat though (17,012 according to the 2016 census).\n\nUntil recently, the neighbourhood has retained a lot of its own character with relatively few chain shops and businesses but we could soon see major change in Tin Wan, just like with its trendy neighbours, Ap Lei Chau and Wong Chuk Hang.\n\nThis is one example of an old Tin Wan shop which has recently closed after decades in business. Let’s hope that Tin Wan can hold on to some of its old charm long into the future.','\n',char(10)),0,'87 Shek Pai Wan Rd, Aberdeen',1,'{"buildingNumberFrom":"87","streetName":"Shek Pai Wan Road","neighbourhood":"Aberdeen","district":"STH","region":"HK","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('3SHUxTLaXa_7','zh-hant','''吉藏可以Yat_Hak__''',1,replace('天灣小區位於香港仔以西，距離香港仔魚類批發市場不遠。 根據1911年嘅人口普查，田灣有111人（ 67名男性）。 今天，它仍然係一個唔錯嘅小社區，附近有舖頭同餐館-不過人口有所增加（根據2016年人口普查為17,012人）。\n\n直到最近，該社區仲保留咗好多自己嘅特色，連鎖店和企業相對較少，但我哋好快就會睇到田灣嘅重大變化，就好似它的時尚鄰居鴨脷洲同黃竹坑一樣。\n\n係一家老天灣店嘅一個例子，該店喺經營咗幾十年後最近關閉。 畀我哋希望天灣能夠喺未來很長一段時間內保持它昔日嘅魅力。','\n',char(10)),1,'石排灣道87號南區',1,'{"buildingNumberFrom":"87","streetName":"石排灣道","neighbourhood":"香港仔","district":"南區","region":null,"country":"香港特區"}');
INSERT INTO featureI18n VALUES('3SHUxTLaXa_7','zh-hans','''吉藏可以Yat_Hak__''',1,replace('天湾小区位于香港仔以西，距离香港仔鱼类批发市场不远。根据 1911 年的人口普查，田湾有 111 人（67 名男性）。今天，它仍然是一个不错的小社区，附近有商店和餐馆 - 不过人口有所增加（根据 2016 年人口普查为 17,012 人）。\n\n直到最近，该社区还保留了很多自己的特色，连锁店和企业相对较少，但我们很快就会看到田湾的重大变化，就像它的时尚邻居鸭脷洲和黄竹坑一样。\n\n这是一家老天湾店的一个例子，该店在经营了几十年后最近关闭。让我们希望天湾能够在未来很长一段时间内保持它昔日的魅力。','\n',char(10)),1,'石排湾道87号南区',1,'{"buildingNumberFrom":"87","streetName":"石排湾道","neighbourhood":"香港人","district":"南区","region":null,"country":"香港特区"}');
INSERT INTO featureI18n VALUES('NTyTgkb_CPyI','en','''Anglo-Chinese Grocery''',0,replace('The little neighbourhood of Tin Wan sits just West of Aberdeen, not far from the Aberdeen Wholesale Fish Market. According to the 1911 census, Tin Wan had 111 people (67 males). Today it’s still a nice little community with neighbourhood shops and restaurants - the population has increased somewhat though (17,012 according to the 2016 census).\n\nUntil recently, the neighbourhood has retained a lot of its own character with relatively few chain shops and businesses but we could soon see major change in Tin Wan, just like with its trendy neighbours, Ap Lei Chau and Wong Chuk Hang.\n\n英華百貨 (Anglo-Chinese Department Store) is one example of an old Tin Wan shop which has recently closed after decades in business. The name may have been grandiose for a corner shop, or si6 do1 (士多), but maybe it embodies the dreams and aspirations of the community it served. Let’s hope that Tin Wan can hold on to some of its old charm long into the future.','\n',char(10)),0,'8 Tin Wan St, Aberdeen',1,'{"buildingNumberFrom":"8","streetName":"Tin Wan Street","neighbourhood":"Aberdeen","district":"STH","region":"HK","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('NTyTgkb_CPyI','zh-hant','閰英中雜貨店 徜徉',1,replace('天灣小區位於香港仔以西，距離香港仔魚類批發市場不遠。 根據1911年嘅人口普查，田灣有111人（ 67名男性）。 今天，它仍然係一個唔錯嘅小社區，附近有舖頭同餐館-不過人口有所增加（根據2016年人口普查為17,012人）。\n\n直到最近，該社區仲保留咗好多自己嘅特色，連鎖店和企業相對較少，但我哋好快就會睇到田灣嘅重大變化，就好似它的時尚鄰居鴨脷洲同黃竹坑一樣。\n\n英華百貨（ Anglo-Chinese Department Store ）係田灣老店嘅一個例子，該店喺經營咗幾十年後最近關閉了。 對於街角舖頭或si6 do1 （士多）來說，呢個名可能好宏偉，但或者它體現了它所服務社區嘅夢想同抱負。 畀我哋希望天灣能夠喺未來很長一段時間內保持它昔日嘅魅力。','\n',char(10)),1,'田灣街8號南區',1,'{"buildingNumberFrom":"8","streetName":"田灣街","neighbourhood":"香港仔","district":"南區","region":null,"country":"香港特區"}');
INSERT INTO featureI18n VALUES('NTyTgkb_CPyI','zh-hans','“英中杂货店”',1,replace('天湾小区位于香港仔以西，距离香港仔鱼类批发市场不远。根据 1911 年的人口普查，田湾有 111 人（67 名男性）。今天，它仍然是一个不错的小社区，附近有商店和餐馆 - 不过人口有所增加（根据 2016 年人口普查为 17,012 人）。\n\n直到最近，该社区还保留了很多自己的特色，连锁店和企业相对较少，但我们很快就会看到田湾的重大变化，就像它的时尚邻居鸭脷洲和黄竹坑一样。\n\n英华百貨 （Anglo-Chinese Department Store） 是田湾老店的一个例子，该店在经营了几十年后最近关闭了。对于街角商店或 si6 do1 （士多） 来说，这个名字可能很宏伟，但也许它体现了它所服务社区的梦想和抱负。让我们希望天湾能够在未来很长一段时间内保持它昔日的魅力。','\n',char(10)),1,'田湾街8号南区',1,'{"buildingNumberFrom":"8","streetName":"田湾街","neighbourhood":"香港人","district":"南区","region":null,"country":"香港特区"}');
