INSERT INTO featureI18n VALUES('fMlemreoiw59','en','Donuts',0,replace('Donut be disappointed to find that there are no delicious pastries to be found here. Only this Ghost Sign for Nuts Donut Shop in Central.\n\nGoogle Maps lists the shop as ‘temporarily closed’ and we hope this is the case because this shop has left a hole in our dessert scene. The photos on their site look delicious and reviews are encouraging: “So far so good laaaaa,” and “it’s like eating cloud.”','\n',char(10)),0,'21 Elgin St, Central District',1,'{"buildingNumberFrom":"21","streetName":"Elgin Street","neighbourhood":"Central District","district":null,"region":"HK","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('fMlemreoiw59','zh-hant','甜甜圈',1,replace('甜甜圈好失望咁發現呢度冇美味嘅糕點。 只有呢間位於中環嘅Ghost Sign for Nuts Donut Shop。\n\n穀謌地圖把呢間店列為≤暫時關閉桎梏，我哋希望係咁，因為呢間店喺我哋嘅甜點界留低咗一個漏洞。 他們網站上的照片看起來不錯，評論也很鼓舞人心：“到目前為止，一切都很好，laaaaa”和“這就像吃雲一樣”。','\n',char(10)),1,'伊利近街21號中西區',1,'{"buildingNumberFrom":"21","streetName":"伊利近街","district":"中西區","region":null,"country":"香港特區"}');
INSERT INTO featureI18n VALUES('fMlemreoiw59','zh-hans','甜甜 圈',1,replace('甜甜圈很失望地发现这里没有美味的糕点。只有这家位于中环的 Ghost Sign for Nuts Donut Shop。\n\n谷歌地图将这家店列为 “暂时关闭”，我们希望是这样，因为这家店在我们的甜点界留下了一个漏洞。他们网站上的照片看起来不错，评论也很鼓舞人心：“到目前为止，一切都很好，laaaaa”和“这就像吃云一样”。','\n',char(10)),1,'伊利近街21号中西区',1,'{"buildingNumberFrom":"21","streetName":"伊利近街","district":"中西区","region":null,"country":"香港特区"}');
