INSERT INTO featureI18n VALUES('xWtBnqOQ5O3P','zh-hans','Soho Hotel（苏豪酒店）',1,'电话号码 ： 225300028',1,'嘉利大厦卑利街48号中西区',1,'{"buildingName":"嘉利大厦","buildingNumberFrom":"48","buildingNumberTo":"52A","streetName":"卑利街","district":"中西区","region":null,"country":"香港特区"}');
INSERT INTO featureI18n VALUES('sWz0VXDuf0T7','en','A-3 Business Center',0,replace('Maybe it was before its time. Maybe it foresaw but was too early for the rise of the gig economy, wider self-employment, the pandemic, and the emergence of sleek co-working spaces.\n\nBut what A-3 Business Center may have lacked in Nespresso machines and designer furniture, it makes up for in Ghost Signs like this one at its Sheung Wan location.\n\nWe’re not 100% sure about whether A-3 still functions. It has a website but even that is a charming remnant from ‘the old internet.’ Who remembers websites that used Flash?','\n',char(10)),0,'28 Wing Lok St, Sheung Wan',1,'{"buildingName":"88 Commercial Building","buildingNumberFrom":"28","streetName":"Wing Lok Street","neighbourhood":"Sheung Wan","district":null,"region":"HK","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('sWz0VXDuf0T7','zh-hant','A-3商務中心',1,replace('或者它早于它的時代。 或者它預見到咗散工經濟嘅興起、更廣泛嘅自僱、大流行病以及時尚嘅聯合辦公空間嘅出現，還為時過早。\n\n但是，A-3 Business Center可能缺乏Nespresso咖啡機同名牌家具，但它喺上環分店嘅Ghost Signs中得到了彌補。\n\n我哋唔可以100%肯定A-3是否仍然有效。 它有一個網站，但即使係咁，都係徜徉舊互聯網≤嘅一個迷人嘅遺蹟。 邊個仲記得使用Flash嘅網站？','\n',char(10)),1,'東成商業大廈永樂街28號中西區',1,'{"buildingName":"東成商業大廈","buildingNumberFrom":"28","streetName":"永樂街","neighbourhood":"上環","district":"中西區","region":null,"country":"香港特區"}');
INSERT INTO featureI18n VALUES('sWz0VXDuf0T7','zh-hans','A-3 商务中心',1,replace('也许它早于它的时代。也许它预见到了零工经济的兴起、更广泛的自雇、大流行病以及时尚的联合办公空间的出现，还为时过早。\n\n但是，A-3 Business Center 可能缺乏 Nespresso 咖啡机和名牌家具，但它在上环分店的 Ghost Signs 中得到了弥补。\n\n我们不能 100% 确定 A-3 是否仍然有效。它有一个网站，但即使是这样，也是 “旧互联网 ”的一个迷人的遗迹。谁还记得使用 Flash 的网站？','\n',char(10)),1,'东成商业大厦永乐街28号中西区',1,'{"buildingName":"东成商业大厦","buildingNumberFrom":"28","streetName":"永乐街","neighbourhood":"上环","district":"中西区","region":null,"country":"香港特区"}');
INSERT INTO featureI18n VALUES('GHFNfxv2K8d6','en','Soho Property',0,replace('Could this Ghost Sign BE any more late 90s? #ripmatthewperry\n\nAt the corner of Staunton Street and the newly hip Peel Street, there is a green and purple artefact from the Y2K era - this could be a Ghost Sign for “The Soho Corner Shop." The rental properties above, which still exist, might also be associated with the sign.\n\nOld Openrice reviews from as long ago as 2007 don’t have great things to say about the bar which explains why Soho Corner Shop has either closed or rebranded as “Corner Bar.”\n\nWhatever happened, it seems to have worked. These days the joint always looks full.\n\nMaybe this could be a cool place for six friends to hang out?','\n',char(10)),0,'14d D Elgin St, Central District',1,'{"buildingNumberFrom":"14D","streetName":"Elgin Street","neighbourhood":"Central District","district":null,"region":"HK","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('GHFNfxv2K8d6','zh-hant','Soho物業',1,replace('呢個Ghost Sign仲會係90年代後期呀？ #ripmatthewperry\n\n在斯湯頓街和新近時尚的皮爾街的拐角處，有一件來自Y2K時代的綠色和紫色文物——這可能是“The Soho Corner Shop”的幽靈標誌。 上述仍然存在嘅出租物業都可能與該標誌相關聯。\n\n早喺2007年，Openrice嘅舊評論就對酒吧冇乜嘢好講嘅，就解釋咗點解Soho Corner Shop已經關閉或更名為“Corner Bar”。\n\n無論發生乜嘢，它似乎都奏效了。 如今，關節看起來總是滿滿的。\n\n或者可能係一個適合六個朋友閒逛嘅好酷嘅地方？','\n',char(10)),1,'伊利近街14D號中西區',1,'{"buildingNumberFrom":"14D","streetName":"伊利近街","district":"中西區","region":null,"country":"香港特區"}');
INSERT INTO featureI18n VALUES('GHFNfxv2K8d6','zh-hans','Soho 物业',1,replace('这个 Ghost Sign 还会是 90 年代后期吗？#ripmatthewperry\n\n在斯汤顿街和新近时尚的皮尔街的拐角处，有一件来自 Y2K 时代的绿色和紫色文物——这可能是“The Soho Corner Shop”的幽灵标志。上述仍然存在的出租物业也可能与该标志相关联。\n\n早在 2007 年，Openrice 的旧评论就对酒吧没有什么好说的，这就解释了为什么 Soho Corner Shop 已经关闭或更名为“Corner Bar”。\n\n无论发生什么，它似乎都奏效了。如今，关节看起来总是满满的。\n\n也许这可能是一个适合六个朋友闲逛的很酷的地方？','\n',char(10)),1,'伊利近街14D号中西区',1,'{"buildingNumberFrom":"14D","streetName":"伊利近街","district":"中西区","region":null,"country":"香港特区"}');
