INSERT INTO featureI18n VALUES('9bbQLMJ5UYGi','en','''Se Wong Hing'' Snake Soup',0,'In Cheung Sha Wan, a phantom snake restaurant sign adorns a noodle shop that occupies the space like a hermit crab in an abandoned shell. The presence of the defunct eatery leaves viewers wondering how many escaped serpents still live in the bowels of that old building.',0,'316 Un Chau St, Cheung Sha Wan',1,'{"buildingNumberFrom":"316","streetName":"Un Chau Street","neighbourhood":"Cheung Sha Wan","district":"SSP","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('9bbQLMJ5UYGi','zh-hant','''Se Wong Hing''蛇湯',1,'在長沙灣，一家麵館嘅招牌上裝飾住個幽靈蛇餐廳嘅招牌，它就好似一隻被遺棄嘅寄居蟹。 呢間已停業嘅餐館嘅存在畀啲觀眾想知棟老建築嘅內部仲生活住幾多逃脫嘅蛇。',1,'元州街316號深水埗區',1,'{"buildingNumberFrom":"316","streetName":"元州街","neighbourhood":"長沙灣","district":"深水埗區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('9bbQLMJ5UYGi','zh-hans','''Se Wong Hing'' 蛇汤',1,'在长沙湾，一家面馆的招牌上装饰着一个幽灵蛇餐厅的招牌，它就像一只被遗弃的寄居蟹。这家已停业的餐馆的存在让观众想知道那栋老建筑的内部还生活着多少逃脱的蛇。',1,'元州街316号深水埗區',1,'{"buildingNumberFrom":"316","streetName":"元州街","neighbourhood":"长沙湾","district":"深水埗區","region":"九龙","country":"香港特区"}');
