INSERT INTO featureI18n VALUES('kH3o7jd9PRm5','en','Po Sang Trading, Fashion Wholesale',0,replace('寶生貿易公司 Po Sang Trading 時裝批發歡迎本港東南亞客出口訂購/__濕打. ''Po Sang Trading, Fashion Wholesale, Welcome Local and Southeast Asian Customers for Export Orders.'' \n\nSham Shui Po, where this sign was found, has a sizeable South East Asian community and the sign seems to specifically cater to them.\n\nUntil late 2023 there was a corresponding sign down the road for the same company. The building that the sign occupied has been refurbished and the facade refinished. That sign has now been covered.','\n',char(10)),0,'69 B Fuk Wing St, Sham Shui Po',1,'{"buildingNumberFrom":"69B","streetName":"Fuk Wing Street","neighbourhood":"Sham Shui Po","district":"SSP","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('kH3o7jd9PRm5','zh-hant','寶生貿易，時裝批發',1,replace('孑生貿易公司Po Sang Trading時裝批發歡迎本港東南亞客出口訂購/__ó打。 雒宝生貿易，時裝批發，歡迎本地同東南亞客戶嚟訂購出口訂單。喏 \n\n發現呢個標誌嘅深水埗有一個相當大嘅東南亞社區，呢個標誌似乎係專門為佢哋服務嘅。\n\n直到2023年底，同一家公司都有一個相應嘅標誌。 標誌所在嘅建築已經翻新，立面都重新粉刷過。 嗰個標誌而家有被覆蓋。','\n',char(10)),1,'福榮街69B號深水埗區',1,'{"buildingNumberFrom":"69B","streetName":"福榮街","neighbourhood":"深水埗","district":"深水埗區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('kH3o7jd9PRm5','zh-hans','宝生贸易， 时装批发',1,replace('寶生貿易公司 Po Sang Trading 時裝批發歡迎本港東南亞客出口訂購/__濕打.“宝生贸易，时装批发，欢迎本地和东南亚客户来订购出口订单。”\n\n发现这个标志的深水埗有一个相当大的东南亚社区，这个标志似乎是专门为他们服务的。\n\n直到 2023 年底，同一家公司都有一个相应的标志。标志所在的建筑已经翻新，立面也重新粉刷过。那个标志现在已经被覆盖了。','\n',char(10)),1,'福荣街69B号深水埗區',1,'{"buildingNumberFrom":"69B","streetName":"福荣街","neighbourhood":"深水埗","district":"深水埗區","region":"九龙","country":"香港特区"}');
