INSERT INTO featureI18n VALUES('-oKwNF45BBEO','en','Pun Shing Laundry',0,replace('Laundry and Dry Cleaning\n\nPhone number : 2307 8652\n\nSeemingly invisible to passers-by unattuned to these relics of the past, such phantom outlines of old signage are sometimes referred to as ‘revenants,’ left behind like an afterimage burned into the signboard, the retina, and the memory.','\n',char(10)),0,'2a A Un Chau St, Sham Shui Po',1,'{"buildingName":"Diamond Building","buildingNumberFrom":"2A","streetName":"Un Chau Street","neighbourhood":"Sham Shui Po","district":"SSP","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('-oKwNF45BBEO','zh-hant','Pun Shing洗衣店',1,replace('洗衣和乾洗\n\n電話號碼：2307 8652\n\n對於唔熟悉呢啲過去遺蹟嘅路人來說，呢啲幻影輪廓似乎係睇唔見嘅，呢種舊標牌嘅幻影輪廓有時被稱為“亡魂”，就好似烙印喺招牌、視網膜和記憶中嘅殘影一樣留低。','\n',char(10)),1,'鑽石樓元州街2A號深水埗區',1,'{"buildingName":"鑽石樓","buildingNumberFrom":"2A","streetName":"元州街","neighbourhood":"深水埗","district":"深水埗區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('-oKwNF45BBEO','zh-hans','Pun Shing 洗衣店',1,replace('洗衣和干洗\n\n电话号码 ： 2307 8652\n\n对于不熟悉这些过去遗迹的路人来说，这些幻影轮廓似乎是看不见的，这种旧标牌的幻影轮廓有时被称为“亡魂”，就像烙印在招牌、视网膜和记忆中的残影一样留下来。','\n',char(10)),1,'钻石楼元州街2A号深水埗區',1,'{"buildingName":"钻石楼","buildingNumberFrom":"2A","streetName":"元州街","neighbourhood":"深水埗","district":"深水埗區","region":"九龙","country":"香港特区"}');
