INSERT INTO featureI18n VALUES('_gKW5FdWSfIA','en','''Shanghai Tung Lo Apartments''',0,replace('Double layered sign with paint peeling off to reveal ''Lu Apartment Shanghai.''\n\nWe lose Ghost Signs all the time but in this case one turned into two! This one in Sham Shui Po (right next to Tim Ho Wan) looked faint in 2019 but a big sheet of paint recently came off to reveal an older, brighter version of the building’s sign underneath.\n\nCheck out Google Street View''s image from 2019 to see what this sign looked like only a few years ago.','\n',char(10)),0,'15 Fuk Wing St, Sham Shui Po',1,'{"buildingNumberFrom":"15","streetName":"Fuk Wing Street","neighbourhood":"Sham Shui Po","district":"SSP","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('_gKW5FdWSfIA','zh-hant','''上海同羅公寓''',1,replace('油漆剝落嘅雙層標誌露出徜徉上海魯公寓徜徉。\n\n我哋一直喺賴幽靈標誌，但喺呢種情況下，一個變成了兩個！ 呢個位於深水埗（就喺添好運旁邊）嘅建築喺2019年睇嚟微弱，但最近一大片油漆脫落，露出下面更舊、更光嘅建築標誌。\n\n查看2019年Google街景嘅圖像，睇吓呢個標誌幾年前係乜嘢樣。','\n',char(10)),1,'福榮街15號深水埗區',1,'{"buildingNumberFrom":"15","streetName":"福榮街","neighbourhood":"深水埗","district":"深水埗區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('_gKW5FdWSfIA','zh-hans','''上海同罗公寓''',1,replace('油漆剥落的双层标志露出“上海鲁公寓”。\n\n我们一直在丢失幽灵标志，但在这种情况下，一个变成了两个！这个位于深水埗（就在添好运旁边）的建筑在 2019 年看起来微弱，但最近一大片油漆脱落，露出下面更旧、更亮的建筑标志。\n\n查看 2019 年 Google 街景的图像，看看这个标志几年前是什么样子。','\n',char(10)),1,'福荣街15号深水埗區',1,'{"buildingNumberFrom":"15","streetName":"福荣街","neighbourhood":"深水埗","district":"深水埗區","region":"九龙","country":"香港特区"}');
INSERT INTO featureI18n VALUES('V6Jgz9QBdF-U','en','''Chung Wah Yeung Bou''',0,'This Mong Kok shop keeps engines purring on Shantung Street and its signage even complements two Ghost Signs. We can’t quite make out the last character but the sign might read "中華洋薄" which would mean “Chinese Foreign Books." Based on the four faded characters on the right, which refer to ''binding'' (possibly 摺線) and ''stapling'' (possibly 釘奘) we think this shop may have specialised in making books rather than selling them.',0,'20 Shantung St, Mong Kok',1,'{"buildingName":"Kwong Yu Building","buildingNumberFrom":"20","streetName":"Shantung Street","neighbourhood":"Mong Kok","district":"YTM","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('V6Jgz9QBdF-U','zh-hant','''Chung Wah Yeung Bou'' （中華楊寶酒店）',1,'呢間旺角店喺山東街上咕嚕咕嚕地叫住，它的招牌甚至與兩個鬼招牌相得益彰。 我們不太能辨認出最後一個字符，但標誌上可能寫著“中華洋薄”，意思是“中國外國書籍”。 根據右邊四個褪色的字，分別是“裝訂”（可能是裝訂）和“裝訂”（可能是釘奘），我們認為這家店可能是專門製作書籍的，而不是賣書的。',1,'廣裕大廈山東街20號油尖旺區',1,'{"buildingName":"廣裕大廈","buildingNumberFrom":"20","streetName":"山東街","neighbourhood":"旺角","district":"油尖旺區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('V6Jgz9QBdF-U','zh-hans','''Chung Wah Yeung Bou'' （中华杨宝酒店）',1,'这家旺角店在山东街上咕噜咕噜地叫着，它的招牌甚至与两个鬼招牌相得益彰。我们不太能辨认出最后一个字符，但标志上可能写着“中华洋薄”，意思是“中国外国书籍”。根据右边四个褪色的字，分别是 “装订” （可能是 装订） 和 “装订” （可能是 釘奘），我们认为这家店可能是专门制作书籍的，而不是卖书的。',1,'广裕大厦山东街20号油尖旺区',1,'{"buildingName":"广裕大厦","buildingNumberFrom":"20","streetName":"山东街","neighbourhood":"旺角","district":"油尖旺区","region":"九龙","country":"香港特区"}');
INSERT INTO featureI18n VALUES('Oh1PSf-L1qJA','en','Bonesetter, ''_Chun Gun''',0,replace('Signs for bonesetters are amongst the most common that we have found in Hong Kong.\n\nTraditional bone-setting is a type of a folk medicine in which practitioners are engaged in joint manipulation. Before the advent of chiropractors, osteopaths and physical therapists, bone-setters were the main providers of this type of treatment. Traditionally, they practiced without any formal training in accepted modern medical procedures. Bone-setters would also reduce joint dislocations and "re-set" bone fractures.','\n',char(10)),0,'20 Shantung St, Mong Kok',1,'{"buildingName":"Kwong Yu Building","buildingNumberFrom":"20","streetName":"Shantung Street","neighbourhood":"Mong Kok","district":"YTM","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('Oh1PSf-L1qJA','zh-hant','跌打師，《_Chun槍》',1,replace('跌打嘅迹象係我哋喺香港發現嘅最常見嘅迹象之一。\n\n傳統跌打係一種民間醫學，從業者參與關節推拿。 在脊醫師、整骨醫生和物理治療師出現之前，跌打師是這種治療的主要提供者。 傳統上，佢哋喺冇任何公認嘅現代醫療程序嘅正式培訓嘅情況下執業。 坐骨術還可以減少關節脫位和“復位”骨折。','\n',char(10)),1,'廣裕大廈山東街20號油尖旺區',1,'{"buildingName":"廣裕大廈","buildingNumberFrom":"20","streetName":"山東街","neighbourhood":"旺角","district":"油尖旺區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('Oh1PSf-L1qJA','zh-hans','跌打师，《_Chun枪》',1,replace('跌打的迹象是我们在香港发现的最常见的迹象之一。\n\n传统跌打是一种民间医学，从业者参与关节推拿。在脊椎按摩师、整骨医生和物理治疗师出现之前，跌打师是这种治疗的主要提供者。传统上，他们在没有任何公认的现代医疗程序的正式培训的情况下执业。坐骨术还可以减少关节脱位和“复位”骨折。','\n',char(10)),1,'广裕大厦山东街20号油尖旺区',1,'{"buildingName":"广裕大厦","buildingNumberFrom":"20","streetName":"山东街","neighbourhood":"旺角","district":"油尖旺区","region":"九龙","country":"香港特区"}');
INSERT INTO featureI18n VALUES('DujhBcPf09CD','en','Illegible Red Under Ki Lung Street Sign',0,'Under Ki Lung Street Sign',0,'36 Ki Lung St, Mong Kok',1,'{"buildingNumberFrom":"36","streetName":"Ki Lung Street","neighbourhood":"Mong Kok","district":"YTM","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('DujhBcPf09CD','zh-hant','基隆路牌下難以辨認嘅紅色',1,'在基隆街牌的',1,'基隆街36號油尖旺區',1,'{"buildingNumberFrom":"36","streetName":"基隆街","neighbourhood":"旺角","district":"油尖旺區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('DujhBcPf09CD','zh-hans','基隆路牌下难以辨认的红色',1,'在基隆街牌下',1,'基隆街 36 号油尖旺区',1,'{"buildingNumberFrom":"36","streetName":"基隆街","neighbourhood":"旺角","district":"油尖旺区","region":"九龙","country":"香港特区"}');
INSERT INTO featureI18n VALUES('MaLkcOsgvs3e','en','''Nam Kee Meat Co.''',0,replace('On Argyle Street in Mong Kok the outline of a Ghost Sign for a defunct butcher’s shop hovers over its successor, as captured in October 2022. \n\nSeemingly invisible to passers-by unattuned to these relics of the past, such phantom outlines of old signage are sometimes referred to as ‘revenants,’ left behind like an afterimage burned into the signboard, the retina, and the memory.','\n',char(10)),0,'7 Argyle St, Mong Kok',1,'{"buildingName":"Kai Wan Building","buildingNumberFrom":"7","streetName":"Argyle Street","neighbourhood":"Mong Kok","district":"YTM","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('MaLkcOsgvs3e','zh-hant','閰南記肉公司徜徉',1,replace('2022年10月，在旺角亞皆老街，一家已停業嘅肉店嘅幽靈標誌輪廓懸停在其繼任者上方。 \n\n對於唔熟悉呢啲過去遺蹟嘅路人來說，呢啲幻影輪廓似乎係睇唔見嘅，呢種舊標牌嘅幻影輪廓有時被稱為“亡魂”，就好似烙印喺招牌、視網膜和記憶中嘅殘影一樣留低。','\n',char(10)),1,'啟運大廈亞皆老街7號油尖旺區',1,'{"buildingName":"啟運大廈","buildingNumberFrom":"7","streetName":"亞皆老街","neighbourhood":"旺角","district":"油尖旺區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('MaLkcOsgvs3e','zh-hans','''南记肉公司''',1,replace('2022 年 10 月，在旺角亚皆老街，一家已停业的肉店的幽灵标志轮廓悬停在其继任者上方。\n\n对于不熟悉这些过去遗迹的路人来说，这些幻影轮廓似乎是看不见的，这种旧标牌的幻影轮廓有时被称为“亡魂”，就像烙印在招牌、视网膜和记忆中的残影一样留下来。','\n',char(10)),1,'启运大厦亚皆老街7号油尖旺区',1,'{"buildingName":"启运大厦","buildingNumberFrom":"7","streetName":"亚皆老街","neighbourhood":"旺角","district":"油尖旺区","region":"九龙","country":"香港特区"}');
