INSERT INTO featureI18n VALUES('I3ZXxyWDXl0u','en','''Cheng Cheong Roast Meats Expert''',0,replace('A Ghost Sign for roasted meat hides behind laundry in Mong Kok, as seen in October 2022. \n\nWhen hunting Ghost Signs, don’t fold if they aren’t immediately obvious. Keep your eyes trained on laundry lines and air conditioning units - the most common haunts for defunct signage.','\n',char(10)),0,'1052 Canton Rd, Mong Kok',1,'{"buildingNumberFrom":"1052","streetName":"Canton Road","neighbourhood":"Mong Kok","district":"YTM","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('I3ZXxyWDXl0u','zh-hant','“Cheng Cheong Roast Meats Expert”',1,replace('2022年10月，旺角嘅洗衣店後便藏住個烤肉嘅鬼牌。 \n\n在尋找Ghost Sign時，如果它們唔係即刻顯而易見的，請不要棄牌。 讓您的眼望住晾衣繩同冷氣機組-係已停業標牌最常見嘅出沒地。','\n',char(10)),1,'廣東道1052號油尖旺區',1,'{"buildingNumberFrom":"1052","streetName":"廣東道","neighbourhood":"旺角","district":"油尖旺區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('I3ZXxyWDXl0u','zh-hans','“Cheng Cheong Roast Meats Expert”',1,replace('2022 年 10 月，旺角的洗衣店后面藏着一个烤肉的鬼牌。\n\n在寻找 Ghost Sign 时，如果它们不是立即显而易见的，请不要弃牌。让您的眼睛盯着晾衣绳和空调机组 - 这是已停业标牌最常见的出没地。','\n',char(10)),1,'广东道1052号油尖旺区',1,'{"buildingNumberFrom":"1052","streetName":"广东道","neighbourhood":"旺角","district":"油尖旺区","region":"九龙","country":"香港特区"}');
