INSERT INTO featureI18n VALUES('kiWiJ7yuYg8F','en','Chinese Meat Company',0,replace('With its sign just visible behind a rolling shutter that was installed later, along with its old terrazzo, this former butcher shop specialising in pork and beef is now occupied by a metalware and fabrication shop. \n\nThis perhaps reflects the changes which this neighbourhood in Mong Kok has seen. The entire street is now full of hardware stores, electrical engineering companies, mechanics and various other businesses of that type.','\n',char(10)),0,'225 Reclamation St, Mong Kok',1,'{"buildingNumberFrom":"225","streetName":"Reclamation Street","neighbourhood":"Mong Kok","district":"YTM","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('kiWiJ7yuYg8F','zh-hant','中國肉類公司',1,replace('呢間以前專門經營豬肉和牛肉嘅肉店，喺後尾安裝嘅捲簾百葉窗後便可以看到它的標誌，而家畀一家金屬器和製造店佔據。 \n\n或許反映咗旺角呢個社區所睇到嘅變化。 成條街而家周圍都係五金舖、電氣工程公司、機械師同各種其他此類企業。','\n',char(10)),1,'新填地街225號油尖旺區',1,'{"buildingNumberFrom":"225","streetName":"新填地街","neighbourhood":"旺角","district":"油尖旺區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('kiWiJ7yuYg8F','zh-hans','中国肉类公司',1,replace('这家以前专门经营猪肉和牛肉的肉店，在后来安装的卷帘百叶窗后面可以看到它的标志，现在被一家金属器和制造店占据。\n\n这或许反映了旺角这个社区所看到的变化。整条街现在到处都是五金店、电气工程公司、机械师和各种其他此类企业。','\n',char(10)),1,'新填地街225号油尖旺区',1,'{"buildingNumberFrom":"225","streetName":"新填地街","neighbourhood":"旺角","district":"油尖旺区","region":"九龙","country":"香港特区"}');
INSERT INTO featureI18n VALUES('Dxga5SQc-fX4','en','Wing Fung St 23A-25',0,replace('A Ghost Sign of the times?\n\nYou can tell the Hong Kong property market is down when even a Midland Realty that has been on this corner in Wan Chai since at least 2008 has to shut its doors.\n\nCaptured while hoarding was up between tenants in late April 2023, workers revealed this beautiful terrazzo sign when they took down the real estate agent’s shop front . We can only make out one word, 保 (bou2 to protect or save) but from Land Registry records, we know that the building was completed in 1957, which means that the sign could potentially be from then.\n\nColourful finishes like terrazzo once played a big role in defining the look of Hong Kong between the 1930s and 1960s, giving it that signature look of a modern metropolis in the making.\n\nIn recent years we''ve seen terrazzo make a huge comeback as a fashionable material. It works well in our hot, humid climate as it''s cool to the touch and on top of functionality, it now comes in wilder colour combinations than ever before.\n\nOnce again, terrazzo has proven itself a material that stands for style and modernity.','\n',char(10)),0,'23 Queen''s Rd East, Wan Chai',1,'{"buildingNumberFrom":"23","streetName":"Queen''s Road East","neighbourhood":"Wan Chai","district":"WC","region":"HK","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('Dxga5SQc-fX4','zh-hant','永豐街23A-25',1,replace('時代嘅幽靈標誌？\n\n你可以看出香港的房地產市場有低迷，即使係至少由2008年開始就喺灣仔呢個角落嘅美聯地產都不得不關門。\n\n2023年4月下旬，工人們喺租戶之間囤積時被捕獲，当他们拆除地產經紀嘅店面時，佢哋展示咗呢個靚嘅水磨石標誌。 我哋只能辨認出一個詞，保（ bou2保護或保存），但由土地註冊處嘅記錄中，我哋知道該建築於1957年完工，意味住該標誌可能係由嗰時起嘅。\n\n水磨石等色彩繽紛嘅飾面曾經喺1930年代至1960年代期間定義香港嘅面貌中發揮了重要作用，賦予了它現代大都市嘅標誌性外觀。\n\n近年來，我哋睇到水磨石作為一種時尚材料捲土重來。 它在炎熱潮濕的氣候中效果很好，因為它摸起來很涼爽，除了功能之外，它現在還有比以往任何時候都更狂野的色彩組合。\n\n水磨石再次證明咗自己係一種代表住風格同現代性嘅材料。','\n',char(10)),1,'皇后大道東23號灣仔區',1,'{"buildingNumberFrom":"23","streetName":"皇后大道東","neighbourhood":"灣仔","district":"灣仔區","region":null,"country":"香港特區"}');
INSERT INTO featureI18n VALUES('Dxga5SQc-fX4','zh-hans','永丰街 23A-25',1,replace('时代的幽灵标志？\n\n你可以看出香港的房地产市场已经低迷了，即使是至少从 2008 年开始就在湾仔这个角落的美联房地产也不得不关门。\n\n2023 年 4 月下旬，工人们在租户之间囤积时被捕获，当他们拆除房地产经纪人的店面时，他们展示了这个美丽的水磨石标志。我们只能辨认出一个词，保（bou2 保护或保存），但从土地注册处的记录中，我们知道该建筑于 1957 年完工，这意味着该标志可能是从那时起的。\n\n水磨石等色彩缤纷的饰面曾经在 1930 年代至 1960 年代期间定义香港的面貌中发挥了重要作用，赋予了它现代大都市的标志性外观。\n\n近年来，我们看到水磨石作为一种时尚材料卷土重来。它在炎热潮湿的气候中效果很好，因为它摸起来很凉爽，除了功能之外，它现在还有比以往任何时候都更狂野的色彩组合。\n\n水磨石再次证明了自己是一种代表着风格和现代性的材料。','\n',char(10)),1,'皇后大道东23号湾仔区',1,'{"buildingNumberFrom":"23","streetName":"皇后大道东","neighbourhood":"湾仔","district":"湾仔区","region":null,"country":"香港特区"}');
INSERT INTO featureI18n VALUES('mDA1w24lfsG2','en','''Tsui Lung Biu General Bonesetter''',0,replace('Signs for bonesetters are amongst the most common that we have found in Hong Kong.\n\nTraditional bone-setting is a type of a folk medicine in which practitioners are engaged in joint manipulation. Before the advent of chiropractors, osteopaths and physical therapists, bone-setters were the main providers of this type of treatment. Traditionally, they practiced without any formal training in accepted modern medical procedures. Bone-setters would also reduce joint dislocations and "re-set" bone fractures.','\n',char(10)),0,'199 A Reclamation St, Yau Ma Tei',1,'{"buildingNumberFrom":"199A","streetName":"Reclamation Street","neighbourhood":"Yau Ma Tei","district":"YTM","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('mDA1w24lfsG2','zh-hant','''Tsui Lung Biu General Bonesetter'' （翠龍標將軍跌打）',1,replace('跌打嘅迹象係我哋喺香港發現嘅最常見嘅迹象之一。\n\n傳統跌打係一種民間醫學，從業者參與關節推拿。 在脊醫師、整骨醫生和物理治療師出現之前，跌打師是這種治療的主要提供者。 傳統上，佢哋喺冇任何公認嘅現代醫療程序嘅正式培訓嘅情況下執業。 坐骨術還可以減少關節脫位和“復位”骨折。','\n',char(10)),1,'新填地街199A號油尖旺區',1,'{"buildingNumberFrom":"199A","streetName":"新填地街","neighbourhood":"油麻地","district":"油尖旺區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('mDA1w24lfsG2','zh-hans','''Tsui Lung Biu General Bonesetter'' （翠龙标将军跌打）',1,replace('跌打的迹象是我们在香港发现的最常见的迹象之一。\n\n传统跌打是一种民间医学，从业者参与关节推拿。在脊椎按摩师、整骨医生和物理治疗师出现之前，跌打师是这种治疗的主要提供者。传统上，他们在没有任何公认的现代医疗程序的正式培训的情况下执业。坐骨术还可以减少关节脱位和“复位”骨折。','\n',char(10)),1,'新填地街199A号油尖旺区',1,'{"buildingNumberFrom":"199A","streetName":"新填地街","neighbourhood":"油麻地","district":"油尖旺区","region":"九龙","country":"香港特区"}');
