INSERT INTO featureI18n VALUES('47ox3TzIyol4','en','''Hip Wo Pawn Shop''',0,replace('This defunct pawn shop sign in Jordan is still legible under a layer of pink paint.  Around the corner of the same building you can see the cut off steel armature which once would have held the establishment''s typical pawn shop neon emblazoned with the word "押" (aat3) against a red background and fringed with green - a stylized bat holding a coin.\n\nOther features of a traditional Hong Kong pawn shop include a “hiding shame board” (遮醜板 ze1 cau2 baan2) just inside the entrance and floors of storage above the ground floor shop where people hocked their prized possesions at a raised counter where a pawnbroker valued the goods.\n\nAccording to a pawnbroker who has worked in the industry for over seven decades, the most commonly pawned items are gold, diamonds, and watches.','\n',char(10)),0,'3 Bowring St, Yau Ma Tei',1,'{"buildingNumberFrom":"3","streetName":"Bowring Street","neighbourhood":"Yau Ma Tei","district":"YTM","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('47ox3TzIyol4','zh-hant','閰協和當舖 唻',1,replace('呢個喺約旦已經停業嘅當舖標誌喺一層粉紅色嘅油漆下仍然清晰可辨。  喺同一棟建築嘅枴角处，你可以睇到被切斷嘅鋼製骨架，它曾經係該機構典型嘅當舖霓虹燈，在紅色背景上印有采押徜徉（ aat3 ）詞，並飾有綠色-一隻攞住硬幣嘅程式化蝙蝠。\n\n傳統香港典當行嘅其他特色包括入口內嘅“遮醜板ze1 cau2 baan2”，就喺入口內同底層舖頭上方嘅士多房地板上，人們將佢哋珍貴嘅物品放喺一個升高嘅櫃枱上，当舖喺嗰度對商品進行估價。\n\n據一位在該行業工作咗七十多年嘅典當商稱，最常見嘅典當物品係黃金、鑽石同手錶。','\n',char(10)),1,'寶靈街3號油尖旺區',1,'{"buildingNumberFrom":"3","streetName":"寶靈街","neighbourhood":"油麻地","district":"油尖旺區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('47ox3TzIyol4','zh-hans','“协和当铺”',1,replace('这个在约旦已经停业的当铺标志在一层粉红色的油漆下仍然清晰可辨。 在同一栋建筑的拐角处，您可以看到被切断的钢制骨架，它曾经是该机构典型的当铺霓虹灯，在红色背景上印有“押”（aat3） 一词，并饰有绿色 - 一只拿着硬币的程式化蝙蝠。\n\n传统香港典当行的其他特色包括入口内的“遮醜板 ze1 cau2 baan2”，就在入口内和底层商店上方的储藏室地板上，人们将他们珍贵的物品放在一个升高的柜台上，当铺在那里对商品进行估价。\n\n据一位在该行业工作了七十多年的典当商称，最常见的典当物品是黄金、钻石和手表。','\n',char(10)),1,'宝灵街3号油尖旺区',1,'{"buildingNumberFrom":"3","streetName":"宝灵街","neighbourhood":"油麻地","district":"油尖旺区","region":"九龙","country":"香港特区"}');
