INSERT INTO featureI18n VALUES('rbPeQwBseZXC','en','Difficult Bonesetter Cases',0,replace('Signs for bonesetters are amongst the most common that we have found in Hong Kong.\n\nTraditional bone-setting is a type of a folk medicine in which practitioners are engaged in joint manipulation. Before the advent of chiropractors, osteopaths and physical therapists, bone-setters were the main providers of this type of treatment. Traditionally, they practiced without any formal training in accepted modern medical procedures. Bone-setters would also reduce joint dislocations and "re-set" bone fractures.','\n',char(10)),0,'328 Shanghai St, Yau Ma Tei',1,'{"buildingName":"On Ku House","buildingNumberFrom":"328","streetName":"Shanghai Street","neighbourhood":"Yau Ma Tei","district":"YTM","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('rbPeQwBseZXC','zh-hant','困難嘅跌打病例',1,replace('跌打嘅迹象係我哋喺香港發現嘅最常見嘅迹象之一。\n\n傳統跌打係一種民間醫學，從業者參與關節推拿。 在脊醫師、整骨醫生和物理治療師出現之前，跌打師是這種治療的主要提供者。 傳統上，佢哋喺冇任何公認嘅現代醫療程序嘅正式培訓嘅情況下執業。 坐骨術還可以減少關節脫位和“復位”骨折。','\n',char(10)),1,'安居樓上海街328號油尖旺區',1,'{"buildingName":"安居樓","buildingNumberFrom":"328","streetName":"上海街","neighbourhood":"油麻地","district":"油尖旺區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('rbPeQwBseZXC','zh-hans','困难的跌打病例',1,replace('跌打的迹象是我们在香港发现的最常见的迹象之一。\n\n传统跌打是一种民间医学，从业者参与关节推拿。在脊椎按摩师、整骨医生和物理治疗师出现之前，跌打师是这种治疗的主要提供者。传统上，他们在没有任何公认的现代医疗程序的正式培训的情况下执业。坐骨术还可以减少关节脱位和“复位”骨折。','\n',char(10)),1,'安居楼上海街328号油尖旺区',1,'{"buildingName":"安居楼","buildingNumberFrom":"328","streetName":"上海街","neighbourhood":"油麻地","district":"油尖旺区","region":"九龙","country":"香港特区"}');
