INSERT INTO featureI18n VALUES('gdMXveYWo4XN','en','''Kam Fa Photo Studio, __Service''',0,replace('Classic red and white colour scheme, neat Clerical Script calligraphy with an air conditioning unit right on top - it doesn''t get more ''HK Ghost Sign'' than this beauty for 金花攝影(gam1 faa1 sip3 jing2 Golden Flower Photography Studio) that we found hovering over a market in Jordan.\n\nIn the past, cameras would have been an impractical luxury for most in Hong Kong. In its day, a trip to ''Golden Flower Photography Studio'' must have been an exciting occasion, hence its correspondingly beautiful painted sign.','\n',char(10)),0,'28 Bowring St, Yau Ma Tei',1,'{"buildingNumberFrom":"28","streetName":"Bowring Street","neighbourhood":"Yau Ma Tei","district":"YTM","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('gdMXveYWo4XN','zh-hant','徜徉金發照相馆，__Service徜徉',1,replace('經典嘅紅白配色方案，工整嘅文員書法，頂部有冷氣-冇過呢件徘徊喺約旦市場上空嘅金花珩（ gam1 faa1 sip3 jing2 Golden Flower Photography Studio ）嘅美女更徜徉香港鬼簽徜徉了。\n\n過去，對於大多數香港人來說，相機係一種不切實際嘅奢侈品。 在那個時代，前往“Golden Flower Photography Studio”一定是一個令人興奮的時刻，因此它相應地擁有美麗的彩繪標誌。','\n',char(10)),1,'寶靈街28號油尖旺區',1,'{"buildingNumberFrom":"28","streetName":"寶靈街","neighbourhood":"油麻地","district":"油尖旺區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('gdMXveYWo4XN','zh-hans','“金发照相馆，__Service”',1,replace('经典的红白配色方案，工整的文员书法，顶部有空调 - 没有比这件徘徊在约旦市场上空的金花攝影（gam1 faa1 sip3 jing2 Golden Flower Photography Studio）的美女更“香港鬼签”了。\n\n过去，对于大多数香港人来说，相机是一种不切实际的奢侈品。在那个时代，前往 “Golden Flower Photography Studio” 一定是一个令人兴奋的时刻，因此它相应地拥有美丽的彩绘标志。','\n',char(10)),1,'宝灵街28号油尖旺区',1,'{"buildingNumberFrom":"28","streetName":"宝灵街","neighbourhood":"油麻地","district":"油尖旺区","region":"九龙","country":"香港特区"}');
