INSERT INTO featureI18n VALUES('GCIAZBx2FDdl','en','School',0,'It''s a permanent recess for this school in Yau Ma Tei. A commercial building’s pink paint cracks away to reveal a vivid green Ghost Sign with a nice old-school font.',0,'10 Parkes St, Yau Ma Tei',1,'{"buildingName":"Parkes Mansion","buildingNumberFrom":"1","buildingNumberTo":"11","streetName":"Parkes Street","neighbourhood":"Yau Ma Tei","district":"YTM","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('GCIAZBx2FDdl','zh-hant','學校',1,'係呢間位於油馬地嘅學校嘅永久休息時間。 商業建築嘅粉紅色油漆開裂，露出一個鮮艷嘅綠色Ghost Sign同靚嘅老式字體。',1,'康寧大廈白加士街1號油尖旺區',1,'{"buildingName":"康寧大廈","buildingNumberFrom":"1","buildingNumberTo":"11","streetName":"白加士街","neighbourhood":"油麻地","district":"油尖旺區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('GCIAZBx2FDdl','zh-hans','学校',1,'这是这所位于油马地的学校的永久休息时间。商业建筑的粉红色油漆开裂，露出一个鲜艳的绿色 Ghost Sign 和漂亮的老式字体。',1,'康宁大厦白加士街1号油尖旺区',1,'{"buildingName":"康宁大厦","buildingNumberFrom":"1","buildingNumberTo":"11","streetName":"白加士街","neighbourhood":"油麻地","district":"油尖旺区","region":"九龙","country":"香港特区"}');
INSERT INTO featureI18n VALUES('g8FpUyZZnhs3','en','''Ah Yuen Tailor Factory''',0,replace('Exploring Yaumatei, this cheeky Ghost Sign peeked out and grabbed our attention straight away.\n\nStill announcing itself loud and proud across Nathan Road is 亞阮洋服 (ngaa3 jyun2 joeng4 fuk6 Ah Yuen Tailor).\n\nOver dinner with Bonny Yuen of Yuen''s Tailor (no relation to the Ah Yuen from the sign), it was explained to us that upstairs tailoring businesses like this were once very common in Hong Kong.\n\nAh Yuen was most likely a one man band. In the day he would probably have made his rounds, going door to door visiting offices and places of business to tout for orders and take measurements. After a long day of doing that, the tailor would return to his workshop and turn those measurements into shirts and suits. He’d probably work all night on those orders. It was a tough business with demanding clients who might not pay if they weren’t completely satisfied.\n\nAccording to Bonny, this kind of business model doesn’t really work in Hong Kong anymore. Tailoring companies in the Mainland are willing to do things for way too cheap and as a result there is no longer enough margin to justify the hours of intense labour involved.\n\nSo long, Ah Yuen. We hope you saw good days. Hope for the best, prepare for the worst and shop local!','\n',char(10)),0,'133 Parkes St, Yau Ma Tei',1,'{"buildingNumberFrom":"133","streetName":"Parkes Street","neighbourhood":"Yau Ma Tei","district":"YTM","region":"KL","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('g8FpUyZZnhs3','zh-hant','''阿園裁縫厂''',1,replace('在探索油麻地時，呢個厚顏無恥嘅鬼星座探出頭來，立即吸引咗我哋嘅注意力。\n\n仍然喺彌敦道對面大聲而自豪地宣告自己嘅係亞阮洋服（ ngaa3 jyun2 joeng4 fuk6 Ah Yuen Tailor ）。\n\n在與Yuen''s Tailor的Bonny Yuen共進晚餐時（與招牌上的阿園無關），他們向我們解釋說，像這樣的樓上裁縫店在香港曾經非常普遍。\n\nAh Yuen好可能係一個單人樂隊。 白天，佢可能會四處走動，挨傢挨戶咁訪問辦公室和營業場所，兜售訂單並進行測量。 經過成日嘅作業之後，裁縫會回到他的工作室，將呢啲尺寸變成恤衫同西裝。 佢可能會為呢啲訂單工作一整夜。 係一項艱難嘅業務，要求苛刻嘅客戶如果唔完全滿意，佢哋可能唔會付款。\n\nBonny表示，呢種商業模式喺香港有行不通。 內地的裁縫公司願意以太便宜的價格做事，因此不再有足夠的利潤來證明所涉及的高強度勞動時間是合理的。\n\n好久了，阿園。 我哋希望您看到了美好嘅日子。 希望最好，為最壞的情況做準備，並喺當地購物！','\n',char(10)),1,'白加士街133號油尖旺區',1,'{"buildingNumberFrom":"133","streetName":"白加士街","neighbourhood":"油麻地","district":"油尖旺區","region":"九龍","country":"香港特區"}');
INSERT INTO featureI18n VALUES('g8FpUyZZnhs3','zh-hans','''阿园裁缝厂''',1,replace('在探索油麻地时，这个厚颜无耻的鬼星座探出头来，立即吸引了我们的注意力。\n\n仍然在弥敦道对面大声而自豪地宣告自己的是亞阮洋服 （ngaa3 jyun2 joeng4 fuk6 Ah Yuen Tailor）。\n\n在与 Yuen''s Tailor 的 Bonny Yuen 共进晚餐时（与招牌上的阿园无关），他们向我们解释说，像这样的楼上裁缝店在香港曾经非常普遍。\n\nAh Yuen 很可能是一个单人乐队。白天，他可能会四处走动，挨家挨户地访问办公室和营业场所，兜售订单并进行测量。经过一整天的作业后，裁缝会回到他的工作室，把这些尺寸变成衬衫和西装。他可能会为这些订单工作一整夜。这是一项艰难的业务，要求苛刻的客户如果不完全满意，他们可能不会付款。\n\nBonny 表示，这种商业模式在香港已经行不通了。内地的裁缝公司愿意以太便宜的价格做事，因此不再有足够的利润来证明所涉及的高强度劳动时间是合理的。\n\n好久了，阿园。我们希望您看到了美好的日子。希望最好，为最坏的情况做准备，并在当地购物！','\n',char(10)),1,'白加士街133号油尖旺区',1,'{"buildingNumberFrom":"133","streetName":"白加士街","neighbourhood":"油麻地","district":"油尖旺区","region":"九龙","country":"香港特区"}');
