INSERT INTO featureI18n VALUES('zmyznIbsuSfJ','zh-hans','''__San__Lap Engineering Co. Ltd.''',1,NULL,0,'高发大厦漆咸道北387号九龙城区',1,'{"buildingName":"高发大厦","buildingNumberFrom":"387","streetName":"漆咸道北","neighbourhood":"红磡","district":"九龙城区","region":"九龙","country":"香港特区"}');
INSERT INTO featureI18n VALUES('ynT3GKNuGvUc','en','''Modern Chinese Medicine College''',0,replace('From the rusty screws and regular border of paint, it looks like this sign for 現代中醫藥堂院 (jin6 doi6 zung1 ji1 joek6 tong4 jyun2 Modern Chinese Medicine Clinic) may have been preserved because it had been covered up by another sign at some point, saving it from being painted over along with the rest of the building it occupies.\n\nBlack and white signs are typical for Chinese medical practitioners in Hong Kong and, interestingly, this practice has extended over to Western medical doctors, who have strict industry rules about advertising - they often have their signs printed very plainly in black lettering on clear perspex.\n\nThe building, Leishun Court, hemmed in by Caroline Hill Road, Haven Street and Leighton Road, is a fascinating warren of businesses old and new - bars, vintage clothing stores and tattoo parlours bump up against old printing presses and garages.\n\nA great spot for wandering and Ghost Sign spotting.','\n',char(10)),0,'119 Leighton Rd, Causeway Bay',1,'{"buildingName":"Congregation House","buildingNumberFrom":"119","streetName":"Leighton Road","neighbourhood":"Causeway Bay","district":"WC","region":"HK","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('ynT3GKNuGvUc','zh-hant','ŋ現代中醫學院黃',1,replace('從生銹嘅螺絲同規則嘅油漆邊框來看，呢個現代中为堂院（ jin6 doi6 zung1 ji1 joek6 tong4 jyun2現代中醫診所）嘅招牌可能被保留咗落嚟，因為它喺某個時候畀另一個招牌遮住咗，避免了它與它所佔據的建築物嘅其餘部分一起被粉刷。\n\n黑白標誌是香港中醫的典型做法，有趣的是，這種做法已經延伸到西醫，他們對廣告有嚴格的行業規定——他們的標誌經常在透明的有機玻璃上以黑色字體非常明顯地印刷。\n\n這座名為Leishun Court嘅建築被Caroline Hill Road、Haven Street同Leighton Road包圍，係一個迷人嘅新舊企業聚集地——酒吧、復古服裝店同紋身店與舊印刷機同車房相映成趣。\n\n一個流浪同發現鬼星座嘅好地方。','\n',char(10)),1,'公理堂大樓禮頓道119號灣仔區',1,'{"buildingName":"公理堂大樓","buildingNumberFrom":"119","streetName":"禮頓道","neighbourhood":"銅鑼灣","district":"灣仔區","region":null,"country":"香港特區"}');
INSERT INTO featureI18n VALUES('ynT3GKNuGvUc','zh-hans','“现代中医学院”',1,replace('从生锈的螺丝和规则的油漆边框来看，这个現代中醫藥堂院（jin6 doi6 zung1 ji1 joek6 tong4 jyun2 现代中医诊所）的招牌可能被保留了下来，因为它在某个时候被另一个招牌遮住了，避免了它与它所占据的建筑物的其余部分一起被粉刷。\n\n黑白标志是香港中医的典型做法，有趣的是，这种做法已经延伸到西医，他们对广告有严格的行业规定——他们的标志经常在透明的有机玻璃上以黑色字体非常明显地印刷。\n\n这座名为 Leishun Court 的建筑被 Caroline Hill Road、Haven Street 和 Leighton Road 包围，是一个迷人的新旧企业聚集地——酒吧、复古服装店和纹身店与旧印刷机和车库相映成趣。\n\n一个流浪和发现鬼星座的好地方。','\n',char(10)),1,'公理堂大楼礼顿道119号湾仔区',1,'{"buildingName":"公理堂大楼","buildingNumberFrom":"119","streetName":"礼顿道","neighbourhood":"铜锣湾","district":"湾仔区","region":null,"country":"香港特区"}');
