INSERT INTO featureI18n VALUES('xOIaip-b4ff8','en','''Chung Hing Meat Wholesale Co.''',0,replace('After decades hidden under an awning, this Quarry Bay butcher shop’s Ghost Sign saw the light of day last week.\n\nThe irony? After years of faithful service, it was this neighborhood fixture that was on the butcher''s block.\n\nRunning a small business in Hong Kong is hard. Rents are high and the price elasticity on everyday essentials like meat is low. For those who own their shop spaces, it’s easy to understand why it would be tempting to trade in the daily grind for an easier life as a landlord.\n\nWithin a week of spotting this Ghost Sign, hoardings were put up and construction was started. A new tenant has taken over the space and we hope they''ll do something that adds to the vibrancy of this neighbourhood.\n\nPrepare for the worst but hope for the best - and shop local where you can.','\n',char(10)),0,'981a A King''s Rd, Quarry Bay',1,'{"buildingName":"Chung Hing Mansion","buildingNumberFrom":"981A","streetName":"King''s Road","neighbourhood":"Quarry Bay","district":"EST","region":"HK","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('xOIaip-b4ff8','zh-hant','''中興肉類批發有限公司''',1,replace('喺屈喺遮陽篷的數十年之後，呢間位於鰂魚涌肉店嘅Ghost Sign上周重見天日。\n\n諷刺嘅係？ 經過多年嘅忠實服務，正是呢個社區嘅固定裝置喺肉店嘅街區。\n\n喺香港經營小企業好困難。 租金高，肉類等日常必需品嘅價錢彈性好低。 對於那些擁有自己舖頭空間嘅人來講，好易理解點解以日常工作換取屋主更輕鬆嘅生活好誘人。\n\n喺發現呢個鬼星座之後嘅一周內，啲人就豎起了圍板並開始施工。 一位新租戶接管咗呢個空間，我哋希望佢哋可以做一些事情嚟增加呢個社區嘅活力。\n\n為最壞的情況做好準備，但希望最好的結果-並喺可能嘅地方購買當地商品。','\n',char(10)),1,'中興大廈英皇道981A號東區',1,'{"buildingName":"中興大廈","buildingNumberFrom":"981A","streetName":"英皇道","neighbourhood":"鰂魚涌","district":"東區","region":null,"country":"香港特區"}');
INSERT INTO featureI18n VALUES('xOIaip-b4ff8','zh-hans','''中兴肉类批发有限公司''',1,replace('在隐藏在遮阳篷下数十年后，这家位于鲗鱼涌肉店的 Ghost Sign 上周重见天日。\n\n讽刺的是？经过多年的忠实服务，正是这个社区的固定装置在肉店的街区。\n\n在香港经营小企业很困难。租金高，肉类等日常必需品的价格弹性很低。对于那些拥有自己商店空间的人来说，很容易理解为什么以日常工作换取房东更轻松的生活很诱人。\n\n在发现这个鬼星座后的一周内，人们就竖起了围板并开始施工。一位新租户接管了这个空间，我们希望他们能做一些事情来增加这个社区的活力。\n\n为最坏的情况做好准备，但希望最好的结果 - 并在可能的地方购买当地商品。','\n',char(10)),1,'中兴大厦英皇道981A号东区',1,'{"buildingName":"中兴大厦","buildingNumberFrom":"981A","streetName":"英皇道","neighbourhood":"鲗鱼涌","district":"东区","region":null,"country":"香港特区"}');
