INSERT INTO featureI18n VALUES('WJUxZyF23xIO','en','Congee & Noodles Restaurant',0,'Captured in September 2022 on the ground floor arcade of Tai On Building in Sai Wan Ho, this sign for a former congee and noodle restaurant also advertises ''hot and cold drinks.'' This eatery has had its day its sign now peeks out from behind shipping boxes and crates from the nearby supermarket.',0,'57 Shau Kei Wan Rd, Sai Wan Ho',1,'{"buildingName":"Tai On Building","buildingNumberFrom":"57","streetName":"Shau Kei Wan Road","neighbourhood":"Sai Wan Ho","district":"EST","region":"HK","country":"HKSAR"}');
INSERT INTO featureI18n VALUES('WJUxZyF23xIO','zh-hant','粥麵餐廳',1,'2022年9月喺西灣河大安大廈地下拱廊拍攝嘅呢個前粥麵館嘅招牌仲宣傳住“冷熱飲品”。 呢間餐館有度過它的一日，它的標誌而家由附近超市嘅運輸箱同板條箱後便探出頭來。',1,'太安樓筲箕灣道57號東區',1,'{"buildingName":"太安樓","buildingNumberFrom":"57","streetName":"筲箕灣道","neighbourhood":"西灣河","district":"東區","region":null,"country":"香港特區"}');
INSERT INTO featureI18n VALUES('WJUxZyF23xIO','zh-hans','粥面餐厅',1,'2022 年 9 月在西湾河大安大厦地下拱廊拍摄的这个前粥面馆的招牌还宣传着“冷热饮品”。这家餐馆已经度过了它的一天，它的标志现在从附近超市的运输箱和板条箱后面探出头来。',1,'太安楼筲箕湾道57号东区',1,'{"buildingName":"太安楼","buildingNumberFrom":"57","streetName":"筲箕湾道","neighbourhood":"西湾河","district":"东区","region":null,"country":"香港特区"}');
